const results = $.steps.queryNotion.response.results || [];
const snippets = [];
results.forEach((block, i) => {
  const type = block.type || '';
  let text = '';
  if (block[type] && block[type].rich_text) {
    text = block[type].rich_text.map(t => t.plain_text || '').join('');
  }
  if (text.trim().length > 10) {
    snippets.push({ index: i + 1, text: text.trim().slice(0, 500), type: type });
  }
});

let snippetSummary = '';
snippets.forEach(s => {
  snippetSummary += s.index + '. [' + s.type + '] ' + s.text.slice(0, 200) + '\n';
});

return { snippets, snippetCount: snippets.length, snippetSummary };

const snippets = $.steps.extractSnippets.output.snippets;
const themes = snippets.slice(0, 5).map(s => s.text.slice(0, 80)).join('; ');
const query = 'LinkedIn thought leadership best practices and trends about: ' + themes;
return { query };

const results = $.steps.researchContext.response.results || [];
let research = '';
results.forEach((r, i) => {
  research += (i + 1) + '. ' + (r.title || '') + '\n   ' + (r.text || '').slice(0, 800) + '\n\n';
});
return { research, sourceCount: results.length };

const snippets = $.steps.extractSnippets.output;
const research = $.steps.compileResearch.output;

let prompt = 'You are a LinkedIn content strategist. Transform the following content snippets into polished, engaging LinkedIn posts. Use the research context to add relevant data points, trends, and depth.\n\n';
prompt += 'CONTENT SNIPPETS (' + snippets.snippetCount + '):\n';
prompt += snippets.snippetSummary + '\n\n';
prompt += 'RESEARCH CONTEXT (' + research.sourceCount + ' sources):\n';
prompt += research.research + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Transform each snippet into a compelling LinkedIn post\n';
prompt += '- Add a strong hook in the first line (pattern interrupt)\n';
prompt += '- Include relevant stats or data from research when possible\n';
prompt += '- Use line breaks for readability\n';
prompt += '- End with a question or CTA to drive engagement\n';
prompt += '- Include 3-5 relevant hashtags per post\n';
prompt += '- Keep each post between 150-300 words\n';
prompt += '- Vary post formats: listicle, story, hot take, how-to\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "posts": [\n';
prompt += '    {\n';
prompt += '      "snippetIndex": 1,\n';
prompt += '      "postContent": "the full LinkedIn post text",\n';
prompt += '      "format": "listicle|story|hot-take|how-to|question",\n';
prompt += '      "hashtags": ["tag1", "tag2"],\n';
prompt += '      "estimatedEngagement": "high|medium|low",\n';
prompt += '      "bestPostingTime": "e.g. Tuesday 9am"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "overallStrategy": "posting strategy recommendation",\n';
prompt += '  "weeklySchedule": "suggested posting cadence"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { posts: [], overallStrategy: raw, weeklySchedule: '' }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Post Content', 'Format', 'Hashtags', 'Est. Engagement', 'Best Time']);
(ai.posts || []).forEach(p => {
  rows.push([today, (p.postContent || '').slice(0, 1500), p.format || '', (p.hashtags || []).join(', '), p.estimatedEngagement || '', p.bestPostingTime || '']);
});
return { rows };

const ai = $.steps.parseAI.output;
const posts = ai.posts || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'LinkedIn Content Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Posts Generated:* ' + posts.length + ' | *Source:* Notion snippets + Exa research' } });
if (ai.overallStrategy) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.overallStrategy.slice(0, 500) } });
}
blocks.push({ type: 'divider' });

posts.slice(0, 5).forEach((p, i) => {
  const engIcon = p.estimatedEngagement === 'high' ? ':fire:' : p.estimatedEngagement === 'medium' ? ':chart_with_upwards_trend:' : ':seedling:';
  let text = engIcon + ' *Post ' + (i + 1) + '* [' + (p.format || '') + '] - ' + (p.bestPostingTime || '') + '\n';
  text += (p.postContent || '').slice(0, 200) + '...\n';
  if (p.hashtags && p.hashtags.length > 0) text += p.hashtags.map(h => '#' + h).join(' ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Posts saved to Google Sheets | Powered by Notion + Exa + Claude AI' }] });
const fallback = 'LinkedIn Content: ' + posts.length + ' posts ready';
return { blocks, fallback };
